Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenResponseIsFailure()
    {
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenIsCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs longer than 5s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("fast")
            });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Reusable fake handler
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;

        public MockHttpMessageHandler(HttpResponseMessage response)
            => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `.Result` or `.GetAwaiter()` needed |
| `[Timeout(ms)]` | Guards against hangs; fails the test if it doesn't complete in time |
| `Assert.ThrowsExceptionAsync<T>` | Proper async exception assertion (not `try/catch`) |
| `CancellationTokenSource` | Tests that cancellation propagates correctly |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over responses |

**Tips:**
- In MSTest v3+, you can also use `[TestMethod(Timeout = 5000)]` as a shorthand.
- For MSTest v4, prefer `Assert.ThrowsExactlyAsync<T>` over `ThrowsExceptionAsync<T>` for stricter type matching.
- Never use `Task.Run` or `.Result` in async tests — just `await` directly.
